def fetch_data(db_path):
    import json
    import sqlite3
    import os

    # 테스트 데이터 (실제 DB 연동 전)
    test_data = {
        "status": "success",
        "captain_score": 1500,
        "nanobot_efficiency": "98%",
        "recent_actions": [
            {"crew": "나노", "action": "진행 보고", "points": 2, "time": "08:30"},
            {"crew": "오프니", "action": "코드 작성", "points": 3, "time": "08:15"},
            {"crew": "데피디", "action": "통신 프로토콜", "points": 5, "time": "07:45"}
        ]
    }

    # 실제 DB 접근 시도 (파일 존재할 경우)
    if os.path.exists(db_path):
        try:
            conn = sqlite3.connect(db_path)
            cursor = conn.cursor()
            # 실제 쿼리 실행 (구조에 맞게 수정 필요)
            cursor.execute("SELECT * FROM disciplinary_records LIMIT 5")
            rows = cursor.fetchall()
            conn.close()

            if rows:
                # 실제 데이터 변환
                test_data["real_data"] = rows
                test_data["data_source"] = "real_database"
        except:
            test_data["data_source"] = "mock_fallback"
    else:
        test_data["data_source"] = "mock_no_db"

    return json.dumps(test_data, ensure_ascii=False)
